/**
 * /context-diff: Shows what messages are in the LLM context
 * before and after compaction.
 *
 * Usage:
 *   1. /context-diff-before  вҖ” dumps current context to stdout
 *   2. /compact
 *   3. /context-diff-after   вҖ” dumps new context to stdout
 *   4. Compare the two files it writes
 */

import {
  convertToLlm,
  serializeConversation,
} from "@earendil-works/pi-coding-agent";

export default function contextDiff(pi: import("@mariozechner/pi-coding-agent").ExtensionAPI) {
  function dumpContext(ctx: import("@mariozechner/pi-coding-agent").ExtensionContext, label: string): string {
    const entries = ctx.sessionManager.getEntries();
    const messages = entries
      .filter((e) => e.type === "message" && "message" in e)
      .map((e) => (e as { message: unknown }).message);

    const llmMessages = convertToLlm(messages);
    const serialized = serializeConversation(llmMessages);

    const output =
      `=== ${label} ===\n` +
      `Entries: ${entries.length}\n` +
      `Messages: ${messages.length}\n` +
      `Tokens (estimated): ${serialized.split(/\s+/).length * 1.3 | 0}\n\n` +
      serialized;

    const fs = require("fs");
    const path = require("path");
    const outFile = path.join(ctx.cwd || "/tmp", `.pi-context-${label}.txt`);
    fs.writeFileSync(outFile, output);
    return outFile;
  }

  pi.registerCommand("context-diff-before", {
    description: "Dump current context to .pi-context-before.txt",
    handler: async (_args, ctx) => {
      const file = dumpContext(ctx, "before");
      ctx.ui.notify(`Context dumped to: ${file}`, "info");
    },
  });

  pi.registerCommand("context-diff-after", {
    description: "Dump post-compaction context to .pi-context-after.txt",
    handler: async (_args, ctx) => {
      const file = dumpContext(ctx, "after");
      ctx.ui.notify(`Context dumped to: ${file}`, "info");
    },
  });

  pi.registerCommand("context-diff", {
    description: "Dump before, compact, dump after, and diff",
    handler: async (_args, ctx) => {
      const beforeFile = dumpContext(ctx, "before");
      ctx.ui.notify(`Running /compact...`, "info");
      // Trigger compaction
      const compactResult = await pi._internal?.compact?.();
      const afterFile = dumpContext(ctx, "after");
      ctx.ui.notify(
        `Done. Files:\n  ${beforeFile}\n  ${afterFile}\n\nRun:\ndiff ${beforeFile} ${afterFile}`,
        "info",
      );
    },
  });
}

