/**
 * /compact-show: Dumps the current compaction summary (if any) so you
 * can see what the LLM is actually being fed.
 *
 * Usage: run /compact-show before and after /compact to compare.
 */

export default function compactShow(pi: import("@mariozechner/pi-coding-agent").ExtensionAPI) {
  pi.registerCommand("compact-show", {
    description: "Show the current compaction summary (what the LLM sees for old context)",
    handler: async (_args, ctx) => {
      const entries = ctx.sessionManager.getEntries();
      const compactionEntries = entries.filter(
        (e) => e.type === "compaction"
      ) as import("@mariozechner/pi-coding-agent").CompactionEntry[];

      if (compactionEntries.length === 0) {
        ctx.ui.notify("No compaction has occurred yet.", "info");
        return;
      }

      // Show the LAST (most recent) compaction entry
      const last = compactionEntries[compactionEntries.length - 1];
      const firstKept = compactionEntries.length > 1
        ? compactionEntries[compactionEntries.length - 2].firstKeptEntryId
        : null;

      const lines = [
        `=== Compaction Summary #${compactionEntries.length} ===`,
        `Tokens replaced: ${last.tokensBefore}`,
        `Keeps messages from: ${last.firstKeptEntryId}`,
        `",
      ];

      ctx.ui.notify(lines.join("\n"), "info");

      // Also dump to file for full comparison
      const fs = await import("fs");
      const path = await import("path");
      const outFile = path.default.join(ctx.cwd || "/tmp", `.pi-compaction-${compactionEntries.length}.txt`);
      fs.default.writeFileSync(outFile, last.summary);
      ctx.ui.notify(`Full summary written to: ${outFile}`, "info");
    },
  });

  pi.registerCommand("compact-diff", {
    description: "Show all compaction summaries and diff them",
    handler: async (_args, ctx) => {
      const entries = ctx.sessionManager.getEntries();
      const compactionEntries = entries.filter(
        (e) => e.type === "compaction"
      ) as import("@mariozechner/pi-coding-agent").CompactionEntry[];

      if (compactionEntries.length < 2) {
        ctx.ui.notify(
          `Only ${compactionEntries.length} compaction(s) exist. Need at least 2 to diff.\nRun /compact again to create another.`,
          "info",
        );
        return;
      }

      const fs = await import("fs");
      const path = await import("path");

      compactionEntries.forEach((entry, i) => {
        const outFile = path.default.join(ctx.cwd || "/tmp", `.pi-compaction-v${i + 1}.txt`);
        fs.default.writeFileSync(outFile, `# Compaction #${i + 1}\nTokens replaced: ${entry.tokensBefore}\n\n${entry.summary}`);
      });

      ctx.ui.notify(
        `Compaction summaries written:\n${compactionEntries.map((_, i) => `  ${path.default.join(ctx.cwd || "/tmp", `.pi-compaction-v${i + 1}.txt`)}`).join("\n")}\n\nRun:\n  diff -u <(cat .pi-compaction-v*.txt)`,
        "info",
      );
    },
  });
}

